INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (2, 2, "調子が上がって\nきたなっ", "vo_minigame_1013_icon_2_002_001", 3000, 1000, "訓練はまだ\nここからですわ", 1, "vo_minigame_1013_icon_1_002_001", 2);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (2, 2, "ほらほら、\nまだいけるだろ？", "vo_minigame_1013_icon_2_003_001", 3000, 5000, "クスクス、悪くない\n流れですわね", 2, "vo_minigame_1013_icon_1_003_001", 2);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, "へへっ、おまえら\nやるじゃねえか！", "vo_minigame_1013_icon_2_004_001", 3000, 10000, "すばらしい\n記録ですわ", 3, "vo_minigame_1013_icon_1_004_001", 2);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, "あたしたちはまだ\n止まらねえぜ！", "vo_minigame_1013_icon_2_005_001", 3000, 10000, "乗りに乗って\nいますわね", 4, "vo_minigame_1013_icon_1_005_001", 3);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, "見てろよ！\nマコト班の快進撃だ！", "vo_minigame_1013_icon_2_005_002", 3000, 10000, "まだまだ行きます\nついてきなさい", 5, "vo_minigame_1013_icon_1_005_002", 3);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, "うおぉぉっ！\n絶好調だぜ！", "vo_minigame_1013_icon_2_005_003", 3000, 10000, "エリコ班の\n本領発揮ですわ！", 6, "vo_minigame_1013_icon_1_005_003", 3);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, "どこまで行けるか\n楽しみだなっ！", "vo_minigame_1013_icon_2_006_001", 3000, 0, "ここからは\n前人未到の領域です！", 7, "vo_minigame_1013_icon_1_006_001", 4);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, "まだ諦めんなよっ", "vo_minigame_1013_icon_2_007_001", 1000, 1, "厄介でしたわ…", 8, "vo_minigame_1013_icon_1_007_001", 5);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, "冷やっとしたぜ…！", "vo_minigame_1013_icon_2_007_002", 1000, 1, "油断大敵です", 9, "vo_minigame_1013_icon_1_007_002", 5);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, "弱音を吐くなっ", "vo_minigame_1013_icon_2_007_003", 1000, 1, "忌々しいっ…", 10, "vo_minigame_1013_icon_1_007_003", 5);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 4, "マコト班集合！", "vo_minigame_1013_icon_2_008_001", 1500, 99, "大所帯ですわね", 11, "vo_minigame_1013_icon_1_008_001", 6);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 4, "連携してくぞ！", "vo_minigame_1013_icon_2_008_002", 1500, 99, "エリコ班へようこそ", 12, "vo_minigame_1013_icon_1_008_002", 6);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (6, 1, "みんなに力を！", "vo_minigame_1013_icon_2_020_001", 3000, 0, "ナナカちゃんに\nお任せあれ", 13, "vo_minigame_1013_icon_1_020_001", 8);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (7, 1, "任せてくれたまえ", "vo_minigame_1013_icon_2_022_001", 3000, 0, "はっはっは！\n任せろ！", 14, "vo_minigame_1013_icon_1_022_001", 9);
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (8, 1, "ほな、いきまひょか", "vo_minigame_1013_icon_2_023_001", 3000, 0, "どんどんいくわよ", 15, "vo_minigame_1013_icon_1_023_001", 10);
